python3 -c "
import re, os

tests_dir = 'forge-cli/tests'
pattern = re.compile(r'^func (Test\w+)\(t \*testing\.T\) \{\n\tt\.Skip\(', re.MULTILINE)

for root, dirs, files in os.walk(tests_dir):
    for f in files:
        if f.endswith('_test.go'):
            path = os.path.join(root, f)
            with open(path) as fh:
                content = fh.read()
            # Find functions whose body is ONLY t.Skip(...)
            # Pattern: func TestXxx(t *testing.T) { t.Skip(...) }
            funcs = re.findall(r'(func (Test\w+)\(t \*testing\.T\) \{\n\tt\.Skip\([^)]*\)\n\})', content)
            for match in funcs:
                print(f'{path}: {match[1]}')
" 2>&1

